javascript:(function () {
 if (document.getElementById('awe-panel')) {
 document.getElementById('awe-panel').style.display = 'block';
 return;
 }
 const CONFIG = {
 DEEPSEEK_API_KEY: 'sk-a4700311dcf940edab100900fbf0f33e',
 DEEPSEEK_API_URL: 'https://api.deepseek.com/v1/chat/completions',
 DEEPSEEK_MODEL: 'deepseek-chat',
 };
 const style = document.createElement('style');
 style.id = 'awe-style';
 style.textContent = `
 #awe-panel {
 position: fixed;
 top: 24px;
 right: 24px;
 width: 300px;
 max-height: 92vh;
 overflow-y: auto;
 background: #fff;
 border-radius: 16px;
 box-shadow: 0 8px 32px rgba(0,0,0,0.14), 0 2px 8px rgba(0,0,0,0.08);
 font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Segoe UI', sans-serif;
 font-size: 14px;
 color: #1f2937;
 z-index: 2147483647;
 border: 1px solid rgba(255,255,255,0.6);
 }
 #awe-panel-header {
 display: flex;
 align-items: center;
 justify-content: space-between;
 padding: 16px 18px;
 background: linear-gradient(135deg, #1a73e8 0%, #0d47a1 100%);
 border-radius: 16px 16px 0 0;
 color: #fff;
 }
 #awe-panel .panel-title {
 display: flex;
 align-items: center;
 gap: 8px;
 font-size: 15px;
 font-weight: 700;
 }
 #awe-panel-toggle {
 background: rgba(255,255,255,0.18);
 border: none;
 color: #fff;
 cursor: pointer;
 font-size: 16px;
 width: 28px;
 height: 28px;
 border-radius: 50%;
 display: flex;
 align-items: center;
 justify-content: center;
 transition: background 0.15s;
 }
 #awe-panel-toggle:hover { background: rgba(255,255,255,0.32); }
 #awe-panel-body {
 padding: 16px;
 display: flex;
 flex-direction: column;
 gap: 12px;
 }
 #awe-panel .awe-btn-group {
 display: grid;
 grid-template-columns: 1fr 1fr;
 gap: 8px;
 }
 #awe-panel .awe-btn {
 display: flex;
 flex-direction: column;
 align-items: center;
 justify-content: center;
 gap: 6px;
 padding: 14px 8px;
 border-radius: 12px;
 border: 1.5px solid transparent;
 cursor: pointer;
 font-weight: 600;
 transition: transform 0.12s, box-shadow 0.12s, background 0.15s;
 text-align: center;
 line-height: 1.3;
 }
 #awe-panel .awe-btn:active { transform: scale(0.96); }
 #awe-panel .btn-icon { font-size: 20px; line-height: 1; }
 #awe-panel .btn-label { font-size: 12px; }
 #awe-panel .awe-btn-primary {
 background: #e8f0fe; border-color: #c5d8fd; color: #1a56db;
 }
 #awe-panel .awe-btn-primary:hover {
 background: #d2e3fc; border-color: #1a73e8;
 box-shadow: 0 2px 8px rgba(26,115,232,0.18);
 }
 #awe-panel .awe-btn-secondary {
 background: #f3f4f6; border-color: #e5e7eb; color: #374151;
 }
 #awe-panel .awe-btn-secondary:hover {
 background: #e5e7eb; border-color: #9ca3af;
 }
 #awe-panel .awe-btn-restore {
 grid-column: 1 / -1;
 flex-direction: row;
 padding: 11px 16px;
 background: #fff7ed; border-color: #fed7aa; color: #c2410c;
 font-size: 13px;
 }
 #awe-panel .awe-btn-restore:hover {
 background: #ffedd5; border-color: #fb923c;
 }
 #awe-panel .awe-btn-restore .btn-icon { font-size: 16px; }
 #awe-panel .status-message {
 padding: 9px 12px;
 border-radius: 8px;
 font-size: 12px;
 font-weight: 500;
 line-height: 1.5;
 }
 #awe-panel .status-info { background:#eff6ff; color:#1d4ed8; border:1px solid #bfdbfe; }
 #awe-panel .status-loading { background:#fffbeb; color:#b45309; border:1px solid #fde68a; }
 #awe-panel .status-success { background:#f0fdf4; color:#15803d; border:1px solid #bbf7d0; }
 #awe-panel .status-error { background:#fef2f2; color:#b91c1c; border:1px solid #fecaca; }
 #awe-result-content {
 background: #f9fafb;
 border: 1px solid #e5e7eb;
 border-radius: 10px;
 padding: 12px 14px;
 min-height: 72px;
 font-size: 13px;
 line-height: 1.65;
 color: #374151;
 }
 #awe-result-content .placeholder {
 color: #9ca3af; font-style: italic; margin: 0; text-align: center; padding: 8px 0;
 }
 #awe-result-content h3 {
 margin: 0 0 8px; font-size: 13px; font-weight: 700; color: #1a73e8;
 }
 #awe-result-content p { margin: 0 0 6px; }
 #awe-result-content p:last-child { margin-bottom: 0; }
 #awe-result-content ul { margin: 6px 0 0; padding-left: 16px; }
 #awe-result-content li { margin-bottom: 5px; }
 #awe-result-content .note { color: #9ca3af; font-size: 11px; margin-top: 6px; }
 `;
 document.head.appendChild(style);
 const panel = document.createElement('div');
 panel.id = 'awe-panel';
 panel.setAttribute('role', 'complementary');
 panel.setAttribute('aria-label', '无障碍增强控制面板');
 panel.innerHTML = `
 <div id="awe-panel-header">
 <div class="panel-title"><span>♿</span><span>无障碍增强</span></div>
 <button id="awe-panel-toggle" aria-label="收起面板">−</button>
 </div>
 <div id="awe-panel-body">
 <div class="awe-btn-group">
 <button class="awe-btn awe-btn-primary" id="awe-btn-summary">
 <span class="btn-icon">📄</span><span class="btn-label">生成页面摘要</span>
 </button>
 <button class="awe-btn awe-btn-primary" id="awe-btn-image">
 <span class="btn-icon">🖼️</span><span class="btn-label">图片语义增强</span>
 </button>
 <button class="awe-btn awe-btn-secondary" id="awe-btn-simplify">
 <span class="btn-icon">✂️</span><span class="btn-label">简化展示</span>
 </button>
 <button class="awe-btn awe-btn-restore" id="awe-btn-restore">
 <span class="btn-icon">↩️</span><span class="btn-label">恢复默认页面</span>
 </button>
 </div>
 <div id="awe-status" class="status-message status-info" role="status" aria-live="polite">
 就绪 — 选择一项功能开始体验
 </div>
 <div id="awe-result-content" aria-live="polite">
 <p class="placeholder">功能结果将显示在这里...</p>
 </div>
 </div>
 `;
 document.body.appendChild(panel);
 function setStatus(msg, type = 'info') {
 const el = document.getElementById('awe-status');
 if (el) { el.textContent = msg; el.className = `status-message status-${type}`; }
 }
 function setResult(html) {
 const el = document.getElementById('awe-result-content');
 if (el) el.innerHTML = html;
 }
 function getPageText() {
 const clone = document.body.cloneNode(true);
 clone.querySelectorAll('script, style, noscript, #awe-panel').forEach(el => el.remove());
 return clone.innerText.replace(/\s+/g, ' ').trim();
 }
 async function callDeepSeek(messages, maxTokens = 300) {
 const res = await fetch(CONFIG.DEEPSEEK_API_URL, {
 method: 'POST',
 headers: {
 'Content-Type': 'application/json',
 'Authorization': `Bearer ${CONFIG.DEEPSEEK_API_KEY}`
 },
 body: JSON.stringify({
 model: CONFIG.DEEPSEEK_MODEL,
 messages,
 temperature: 0.5,
 max_tokens: maxTokens
 })
 });
 if (!res.ok) {
 const err = await res.json();
 throw new Error(err.error?.message || res.status);
 }
 const data = await res.json();
 return data.choices[0].message.content.trim();
 }
 async function handleSummary() {
 setStatus('正在提取页面内容...', 'loading');
 setResult('<p class="placeholder">生成中，请稍候...</p>');
 const text = getPageText();
 if (!text) {
 setStatus('未能提取到页面文本', 'error');
 return;
 }
 const truncated = text.length > 3000 ? text.substring(0, 3000) + '...' : text;
 setStatus('正在调用 AI 生成摘要...', 'loading');
 try {
 const summary = await callDeepSeek([
 { role: 'system', content: '你是一个网页内容摘要助手。请用简洁的语言总结网页的核心内容，包括：1) 这是什么页面 2) 主要内容是什么 3) 用户可以做什么。控制在 100 字以内。' },
 { role: 'user', content: `请总结以下网页内容：\n\n${truncated}` }
 ]);
 setResult(`<h3>📄 页面摘要</h3><p>${summary}</p>`);
 setStatus('摘要生成完成', 'success');
 } catch (e) {
 setStatus('生成失败: ' + e.message, 'error');
 setResult(`<p class="placeholder">❌ ${e.message}</p>`);
 }
 }
 async function handleImageEnhance() {
 const images = Array.from(document.querySelectorAll('img')).filter(img =>
 !img.closest('#awe-panel') && (img.naturalWidth || img.width) > 50
 );
 if (images.length === 0) {
 setStatus('当前页面未找到有效图片', 'info');
 setResult('<p class="placeholder">没有找到需要增强的图片。</p>');
 return;
 }
 const total = Math.min(images.length, 5);
 setStatus(`找到 ${images.length} 张图片，正在处理前 ${total} 张...`, 'loading');
 const results = [];
 for (let i = 0; i < total; i++) {
 const img = images[i];
 const existingAlt = img.alt ? img.alt.trim() : '';
 let desc;
 if (existingAlt.length > 2) {
 desc = `已有描述：${existingAlt}`;
 } else {
 setStatus(`正在处理第 ${i + 1}/${total} 张图片...`, 'loading');
 try {
 const parent = img.parentElement;
 const surroundingText = parent
 ? parent.innerText.replace(/\s+/g, ' ').trim().substring(0, 200)
 : '';
 desc = await callDeepSeek([{
 role: 'user',
 content: `你是网页无障碍助手，请根据以下信息为图片生成一句简洁的中文 alt 描述（20字以内，不要加引号）：\n- 图片 URL：${img.src}\n- 尺寸：${img.naturalWidth || img.width}×${img.naturalHeight || img.height}px\n- 周边文本：${surroundingText || '无'}\n\n只输出描述文字本身。`
 }], 60);
 } catch (e) {
 desc = img.src.split('/').pop().split('?')[0];
 }
 img.setAttribute('alt', desc);
 img.setAttribute('title', desc);
 }
 results.push(`<li><strong>图片 ${i + 1}：</strong>${desc}</li>`);
 }
 setResult(`<h3>🖼️ 图片语义增强结果</h3><ul>${results.join('')}</ul>${images.length > 5 ? `<p class="note">仅展示前 5 张，共 ${images.length} 张</p>` : ''}`);
 setStatus('图片语义增强完成', 'success');
 }
 const hiddenEls = [];
 let simplified = false;
 function handleSimplify() {
 if (simplified) {
 hiddenEls.forEach(el => { el.style.display = ''; });
 hiddenEls.length = 0;
 simplified = false;
 document.querySelector('#awe-btn-simplify .btn-label').textContent = '简化展示';
 setStatus('已恢复原始页面', 'info');
 setResult('<p class="placeholder">已退出简化模式。</p>');
 return;
 }
 const selectors = ['nav', 'header', 'footer', 'aside',
 '[class*="sidebar"]', '[class*="banner"]', '[class*="ad"]', '[class*="popup"]',
 '[id*="sidebar"]', '[id*="banner"]'];
 selectors.forEach(sel => {
 document.querySelectorAll(sel).forEach(el => {
 if (!el.closest('#awe-panel') && el.style.display !== 'none') {
 el.style.display = 'none';
 hiddenEls.push(el);
 }
 });
 });
 simplified = true;
 document.querySelector('#awe-btn-simplify .btn-label').textContent = '恢复展示';
 setStatus(`已隐藏 ${hiddenEls.length} 个干扰元素`, 'success');
 setResult(`<h3>✂️ 简化展示</h3><p>已隐藏 ${hiddenEls.length} 个导航/侧栏/页脚等干扰区域。</p><p>点击「恢复默认页面」可撤销。</p>`);
 }
 function handleRestore() {
 if (simplified) {
 hiddenEls.forEach(el => { el.style.display = ''; });
 hiddenEls.length = 0;
 simplified = false;
 document.querySelector('#awe-btn-simplify .btn-label').textContent = '简化展示';
 }
 setStatus('已恢复页面原始状态', 'success');
 setResult('<p class="placeholder">所有增强效果已撤销。</p>');
 }
 document.getElementById('awe-btn-summary').addEventListener('click', handleSummary);
 document.getElementById('awe-btn-image').addEventListener('click', handleImageEnhance);
 document.getElementById('awe-btn-simplify').addEventListener('click', handleSimplify);
 document.getElementById('awe-btn-restore').addEventListener('click', handleRestore);
 document.getElementById('awe-panel-toggle').addEventListener('click', function () {
 const body = document.getElementById('awe-panel-body');
 const collapsed = body.style.display === 'none';
 body.style.display = collapsed ? '' : 'none';
 this.textContent = collapsed ? '−' : '+';
 });
})();